// FETCH CYCLE MICROOPERATIONS
// Step 1: Transfer address from PC to MAR
MAR ← PC

// Step 2: Memory read - fetch instruction from memory
READ_MEMORY
MBR ← MEMORY[MAR]

// Step 3: Transfer instruction to IR
IR ← MBR

// Step 4: Increment PC to point to next instruction
PC ← PC + 1

#include <stdio.h>

// CPU Registers
int PC;        // Program Counter
int IR;        // Instruction Register (opcode in lower 8 bits, address in upper 8)
int MAR;       // Memory Address Register
int MBR;       // Memory Buffer Register
int ACC;       // Accumulator

// Simple memory (256 words)
int memory[256];

// Initialize memory with sample program
void init_memory() {
    memory[0] = 0x010A;  // LOAD 10 (opcode=1, addr=10)
    memory[1] = 0x0205;  // ADD 5 (opcode=2, addr=5)
    memory[2] = 0x0364;  // STORE 100 (opcode=3, addr=100)
    memory[3] = 0x0000;  // HALT
    memory[10] = 15;    // Data at address 10
    memory[5] = 7;      // Data at address 5
}

// FETCH Phase
void fetch() {
    MAR = PC;           // PC -> MAR
    MBR = memory[MAR];  // Read from memory
    IR = MBR;           // MBR -> IR
    PC = PC + 1;        // PC + 1 -> PC
    printf("Fetch: IR=%04X, PC=%d\n", IR, PC);
}

// DECODE Phase
int decode() {
    int opcode = IR & 0x00FF;     // Extract opcode
    int address = (IR >> 8) & 0x00FF;  // Extract address
    printf("Decode: opcode=%d, address=%d\n", opcode, address);
    return opcode;
}

// EXECUTE Phase
void execute(int opcode) {
    int address = (IR >> 8) & 0x00FF;

    switch(opcode) {
        case 1: // LOAD
            ACC = memory[address];
            printf("LOAD: ACC=%d\n", ACC);
            break;
        case 2: // ADD
            ACC = ACC + memory[address];
            printf("ADD: ACC=%d\n", ACC);
            break;
        case 3: // STORE
            memory[address] = ACC;
            printf("STORE: M[%d]=%d\n", address, ACC);
            break;
        default:
            printf("HALT\n");
    }
}

int main() {
    PC = 0;
    init_memory();

    printf("=== Instruction Cycle Simulation ===\n");

    while (1) {
        printf("\n--- Cycle ---\n");
        fetch();
        int opcode = decode();
        if (opcode == 0) break;  // HALT
        execute(opcode);
    }

    printf("\nFinal: ACC=%d, Memory[100]=%d\n", ACC, memory[100]);
    return 0;
}

public class CPU {
    // CPU Registers
    private int PC;        // Program Counter
    private int IR;        // Instruction Register
    private int MAR;       // Memory Address Register  
    private int MBR;       // Memory Buffer Register
    private int ACC;       // Accumulator

    // Main memory
    private int[] memory;

    public CPU() {
        memory = new int[256];
        PC = 0;
    }

    // LOAD instruction into memory
    public void loadProgram(int[] program, int startAddr) {
        for (int i = 0; i < program.length; i++) {
            memory[startAddr + i] = program[i];
        }
    }

    // FETCH: Get instruction from memory
    private void fetch() {
        MAR = PC;                    // PC -> MAR
        MBR = memory[MAR];           // Memory[MAR] -> MBR
        IR = MBR;                    // MBR -> IR
        PC = PC + 1;                 // PC + 1 -> PC
        System.out.println("FETCH: Instruction=" + IR + " loaded into IR");
    }

    // DECODE: Interpret the instruction
    private int[] decode() {
        int opcode = IR / 1000;      // First digit is opcode
        int address = IR % 1000;     // Last 3 digits are address
        System.out.println("DECODE: opcode=" + opcode + ", address=" + address);
        return new int[]{opcode, address};
    }

    // EXECUTE: Perform the operation
    private void execute(int opcode, int address) {
        switch(opcode) {
            case 1: // LOAD: Load from memory to ACC
                ACC = memory[address];
                System.out.println("EXECUTE LOAD: ACC=" + ACC);
                break;
            case 2: // ADD: Add memory value to ACC
                ACC = ACC + memory[address];
                System.out.println("EXECUTE ADD: ACC=" + ACC);
                break;
            case 3: // STORE: Store ACC to memory
                memory[address] = ACC;
                System.out.println("EXECUTE STORE: M[" + address + "]=" + ACC);
                break;
            case 9: // HALT
                System.out.println("EXECUTE: Program Halted");
                break;
        }
    }

    // Complete instruction cycle
    public void runInstruction() {
        fetch();
        int[] decoded = decode();
        execute(decoded[0], decoded[1]);
    }

    // Run program
    public void run() {
        System.out.println("=== Starting CPU Execution ===");
        while (PC < memory.length) {
            runInstruction();
            // Check for halt (opcode 9)
            if (IR == 9000) break;
        }
    }

    public static void main(String[] args) {
        CPU cpu = new CPU();
        // Load program: LOAD 50, ADD 51, STORE 99, HALT
        cpu.loadProgram(new int[]{1050, 2051, 3099, 9000}, 0);
        cpu.loadProgram(new int[]{10, 20}, 50);  // Data

        cpu.run();
        System.out.println("\nFinal ACC: " + cpu.ACC);
    }
}
